head.script:
//-------------------------------------------------------------------------
// 화면 로딩
//-------------------------------------------------------------------------
scwin.onpageload = function() {
    scwin.params = $c.data.getParameter();
    scwin.loUpperLobranCd = $c.gus.cfIsNull(scwin.params.loUpperLobranCd)?  "" : scwin.params.loUpperLobranCd;
    scwin.userClsCd	      = $c.gus.cfIsNull(scwin.params.userClsCd)?        "" : scwin.params.userClsCd; 
    scwin.loginClntNo 	  = $c.gus.cfIsNull(scwin.params.loginClntNo)?      "" : scwin.params.loginClntNo;	
    scwin.loginClntNm 	  = $c.gus.cfIsNull(scwin.params.loginClntNm)?      "" : scwin.params.loginClntNm;	

    //공통코드 조회
	const codeOptions = [
		{ grpCd : "ZZ210", compID : "gr_vehiclesList:eqKndCd" }, 
		{ grpCd : "ZZ208", compID : "gr_vehiclesList:eqNrmCd"  } 
	];
	$c.data.setCommonCode(codeOptions);

    const comboOptions = [
        {
            method : "getLuxeComboData", 
            param1 : "WorkImplementEBC", 
            param2 : "retriveLobran2CodeList",
            param3 : ["1"],
            compID : "lc_srchLobranCd" 
        }
    ];
    $c.data.setGauceUtil(comboOptions);
}

//-------------------------------------------------------------------------
// UDC 로딩
//-------------------------------------------------------------------------
scwin.onUdcCompleted = function() {
    ica_srchDate.setValue($c.date.getServerDateTime());
    $c.data.setPopupTitle("권역별운행차량");
}

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_retrieve = async function () {
    let chkVale = await $c.gus.cfValidate(ica_srchDate)
	if(!chkVale) {
      	ica_srchDate.focus();
      	return;
  	}

    $c.sbm.execute(sbm_retrieve);
}

//-------------------------------------------------------------------------
// 엑셀 다운
//-------------------------------------------------------------------------
scwin.f_down = async function() {
    if(ds_transWrkResult.getTotalRow() == 0) return;
    let conf = await $c.win.confirm("EXCEL로 다운로드 받으시겠습니까?");
    if(conf) {
        var options = {
            fileName  : "차량운행현황.xlsx",
            sheetName : "차량운행현황",
            type      : "4+8+16",
            useSubTotal : "true",
            useSubTotalData : "true",
        };

        $c.data.downloadGridViewExcel(gr_transWrkResult, options);
    }
}

scwin.f_downDtl = async function() {
    if(ds_transWrkResult.getTotalRow() == 0) return;
    let conf = await $c.win.confirm("EXCEL로 다운로드 받으시겠습니까?");
    if(conf) {
        var options = {
            fileName  : "차량상세정보.xlsx",
            sheetName : "차량상세정보",
            type      : "4+8+16",
            useSubTotal : "true",
            useSubTotalData : "true",
        };

        $c.data.downloadGridViewExcel(gr_vehiclesList, options);
    }
}

//-------------------------------------------------------------------------
// Formatter
//-------------------------------------------------------------------------
scwin.f_customFormatter = function(data, formattedData, rowIndex, colIndex) {
    let columnId =  $c.util.getComponent(this.id).getColumnID(colIndex);

    if(columnId == "emptvehclCnt") {
        data = (data == "0")? "" : data;
        return $c.num.formatNumber(data);
    } else if(columnId == "cntrCnt") {  
        if(data == "0") gr_transWrkResult.setCellClass(rowIndex, columnId, "")
        else            gr_transWrkResult.setCellClass(rowIndex, columnId, "underline txt-blue")
    } else if (columnId=="bulkCnt") {
        if(data == "0") gr_transWrkResult.setCellClass(rowIndex, columnId, "")
        else            gr_transWrkResult.setCellClass(rowIndex, columnId, "underline txt-blue")
    } 

    return $c.num.formatNumber(data);
};

scwin.f_displayFormatter = function(data) {
    data = (data == "0")? "" : data;
    return $c.num.formatNumber(data);
}

/* ----------------------------------------------------------------------------
  T R A N S A C T I O N   C O M P O N E N T S   D E C L A R A T I O N
------------------------------------------------------------------------------*/
//차량운행현황 조회 완료
scwin.sbm_retrieve_submitdone = function (e) {
    console.log("scwin.sbm_retrieve_submitdone");
	if (e.responseJSON.resultDataSet[0].Code < 0) return; 

    if(ds_transWrkResult.getTotalRow() > 0) {
        let idx = ds_transWrkResult.getMatchedIndex("lbsLobranCd", "");
        ds_transWrkResult.removeRows(idx);
    }

    spn_totalRow.setValue(ds_transWrkResult.getTotalRow());
};

//차량상세정보 조회 완료
scwin.sbm_vehiclesRetrieve_submitdone = function (e) {
    console.log("scwin.sbm_vehiclesRetrieve_submitdone");
	if (e.responseJSON.resultDataSet[0].Code < 0) return; 

    let rowCnt = ds_vehiclesList.getTotalRow();
    spn_totalRowDtl.setValue(rowCnt);
};

/* ----------------------------------------------------------------------------
  C O M P O N E N T' S   E V E N T S  
-----------------------------------------------------------------------------*/
//조회조건 clear 버튼
scwin.btn_clear_onclick = function (e) {
    scwin.onUdcCompleted();
};

//조회 버튼
scwin.btn_search_onclick = function (e) {
    scwin.f_retrieve();
};

//차량운행현황 그리드 더블 클릭
scwin.gr_transWrkResult_oncelldblclick = function (rowIndex, columnIndex, columnId) {
    rowIndex = ds_transWrkResult.getRowPosition();
    if (Number(ds_transWrkResult.getCellData(ds_transWrkResult.getRowPosition(), columnId)) > 0) {
	    if(ds_transWrkResult.getRowStatus(rowIndex) == "R") {
		    if(    columnId == "emptvehclCnt" || columnId == "cntrCnt" || columnId == "bulkCnt" 
                || columnId == "emptvehclCntMb" || columnId == "cntrCntMb" || columnId == "bulkCntMb") {

                dma_search.set("lbsLobranCd", ds_transWrkResult.getCellData(rowIndex, "lbsLobranCd"));
                dma_search.set("schDate"    , ica_srchDate.getValue());
                if(columnId == "emptvehclCnt" || columnId == "cntrCnt" || columnId == "bulkCnt") {
                    dma_search.set("directVehclMgntYn", "Y");
                    dma_search.set("dptDistrictCd"    , ds_transWrkResult.getCellData(rowIndex, "dptDistrictCd"));

                    if(columnId == "emptvehclCnt")
                        dma_search.set("vehclGubun", "");
                    else if(columnId == "cntrCnt")
                        dma_search.set("vehclGubun", "C");
                    else if(columnId == "bulkCnt")
                        dma_search.set("vehclGubun", "B");
                } else if(columnId == "emptvehclCntMb" || columnId == "cntrCntMb" || columnId == "bulkCntMb") {

                    dma_search.set("directVehclMgntY", "N");
                    dma_search.set("dptDistrictCd", ds_transWrkResult.getCellData(rowIndex, "dptDistrictCdMb"));

                    if(columnId == "emptvehclCntMb")
                        dma_search.set("vehclGubun", "");
                    else if(columnId == "cntrCntMb")
                        dma_search.set("vehclGubun", "C");
                    else if(columnId == "bulkCntMb")
                        dma_search.set("vehclGubun", "B");						
                }

                $c.sbm.execute(sbm_vehiclesRetrieve);
            }
        }
	}
};

//차량상세정보 그리드 더블 클릭
scwin.gr_vehiclesList_oncelldblclick = function (rowIndex, columnIndex, columnId) {
    var v_odrKndCd = ds_vehiclesList.getCellData(rowIndex, "odrKndCd");
    var strOrderDetailUrl = "";
    let programId = "";
    let paramObj = {
          PARAM_MAINTAIN_YN : "N"
        , odrNo             : ds_vehiclesList.getCellData(rowIndex, "odrNo")
        , linkPage          : "odrList"
    };

   if (v_odrKndCd == "C1" || v_odrKndCd == "CS" || v_odrKndCd == "CT" ){                                // 오더 종류가 C1,CS,CT 인 경우
		strOrderDetailUrl = "/ui/tn/sd/odrmgnt/cntrodrreg/tn_201_02_05b.xml";
        programId = "tn_201_02_05b.jsp"

        $c.win.openMenu("수입본선오더", strOrderDetailUrl, programId, paramObj);
	} else if (v_odrKndCd == "C2" || v_odrKndCd == "CX") {                                              // 오더 종류가 C2,CX 인 경우
        strOrderDetailUrl = "/ui/tn/sd/odrmgnt/cntrodrreg/tn_201_02_03b.xml";
        programId = "tn_201_02_03b.jsp"

        $c.win.openMenu("수입일반오더", strOrderDetailUrl, programId, paramObj);
	} else if (v_odrKndCd == "C3" || v_odrKndCd == "CW" || v_odrKndCd == "CR" || v_odrKndCd == "CP") {  // 오더 종류가 C3,CW,CR,CP 인 경우
        strOrderDetailUrl = "/ui/tn/sd/odrmgnt/cntrodrreg/tn_201_02_06b.xml";
        programId = "tn_201_02_06b.jsp"

        $c.win.openMenu("수출본선오더", strOrderDetailUrl, programId, paramObj);
	} else if (v_odrKndCd == "C4") {                                                                    // 오더 종류가 C4 인 경우
		strOrderDetailUrl = "/ui/tn/sd/odrmgnt/cntrodrreg/tn_201_02_04b.xml";
        programId = "tn_201_02_04b.jsp"

        $c.win.openMenu("수출일반오더", strOrderDetailUrl, programId, paramObj);
	} else if (v_odrKndCd == "C5" || v_odrKndCd == "C6" || v_odrKndCd == "C7") {                        // 오더 종류가 C5,C6,C7 인 경우
		strOrderDetailUrl = "/ui/tn/sd/odrmgnt/cntrodrreg/tn_201_02_07b.xml";
        programId = "tn_201_02_07b.jsp"

        $c.win.openMenu("기타오더", strOrderDetailUrl, programId, paramObj);
	} else if (v_odrKndCd == "B2" || v_odrKndCd == "B4" || v_odrKndCd == "D1" || v_odrKndCd == "D2" || v_odrKndCd == "D3" || v_odrKndCd == "D4" || v_odrKndCd == "D6") { 
                                                                                                        // 오더 종류가 B2,B4,D1,D2,D3,D4,D6 인 경우
		strOrderDetailUrl = "/ui/tn/sd/odrmgnt/bulkodrreg/tn_202_02_05b.xml";
        programId = "tn_202_02_05b.jsp"

        $c.win.openMenu("벌크오더", strOrderDetailUrl, programId, paramObj);
    } else if(v_odrKndCd == "DJ"){
        strOrderDetailUrl = "/ui/tn/tp/dongbusteel/tp_201_01_02t.xml";
        programId = "tp_201_01_02t.jsp"

        $c.win.openMenu("오더요청등록(제강)", strOrderDetailUrl, programId, paramObj);
	} else {
		$c.win.alert("공차를 선택했습니다.");
	}    
};
